<template>
  <div class="alert-inner-container">
    <div class="top-section">
      <div class="map-area" ref="geoMap"></div>

      <div class="right-panel">
        <div class="radar-area" ref="radarChart"></div>

        <div class="summary-area">
          <h3 class="section-title">安全防御引擎状态</h3>
          <div class="status-banner">
            <span class="pulse-ring"></span>
            <span class="banner-text">Heuristic IDS 启发式多维巡检中</span>
          </div>

          <div class="stats-grid">
            <div class="stat-box">
              <span class="label">累计拦截 (次)</span>
              <span class="value default">{{ alerts.length }}</span>
            </div>
            <div class="stat-box danger-box">
              <span class="label">高危致命 (次)</span>
              <span class="value danger">{{ highRiskCount }}</span>
            </div>
          </div>
        </div>
      </div>
    </div>

    <div class="bottom-section">
      <div class="table-header">
        <h3 class="section-title">实时安全告警日志 (SecLog)</h3>
      </div>

      <div class="table-scroll-area">
        <table>
          <thead>
            <tr>
              <th>时间</th>
              <th>威胁类型与特征</th>
              <th>攻击源 (IP)</th>
              <th>源区域</th>
              <th>地理溯源</th>
              <th>目标 (IP)</th>
              <th>载荷</th>
              <th>包数</th>
              <th>危险等级</th>
              <th>动作</th>
            </tr>
          </thead>
          <tbody>
            <tr v-for="(item, index) in reversedAlerts" :key="index">
              <td class="time-text">{{ item.time }}</td>
              <td class="threat-text">
                <span class="emoji">{{ item.icon }}</span> {{ item.type }}
              </td>
              <td class="ip-text">{{ item.src_ip }}</td>
              <td><span class="zone-tag-alert">{{ item.src_zone || '外部网络' }}</span></td>
              <td><span class="geo-tag">{{ formatGeo(item.geo) }}</span></td>
              <td class="ip-dst-text">{{ item.dst_ip || 'N/A' }}</td>
              <td class="bytes-text">{{ item.bytes ? formatBytes(item.bytes) : '--' }}</td>
              <td class="packets-text">{{ item.packets || '--' }}</td>
              <td>
                <span :class="['level-badge', item.level]">
                  {{ item.level === 'high' ? '高危' : (item.level === 'medium' ? '中危' : '低危') }}
                </span>
              </td>
              <td class="action-text"><span class="dot safe"></span> 阻断</td>
            </tr>
            <tr v-if="alerts.length === 0">
              <td colspan="10" class="empty-state">
                <div class="empty-icon">✨</div>
                <p>当前网络环境纯净，暂无威胁告警</p>
              </td>
            </tr>
          </tbody>
        </table>
      </div>
    </div>
  </div>
</template>

<script>
import * as echarts from 'echarts';

export default {
  name: 'Alert',
  props: { alerts: { type: Array, default: () => [] } },
  data() {
    return {
      radarInstance: null,
      mapInstance: null,
      mapRegistered: false,
      geoPoints: [],
      geoTimer: null
    }
  },
  computed: {
    reversedAlerts() { return [...this.alerts].reverse(); },
    highRiskCount() { return this.alerts.filter(a => a.level === 'high').length; },
    threatStats() {
      const stats = { 'DDoS攻击': 0, '端口扫描': 0, '蠕虫病毒': 0, '异常爬虫': 0, '数据外泄': 0 };
      this.alerts.forEach(item => { if (stats[item.category] !== undefined) stats[item.category]++; });
      return stats;
    }
  },
  watch: {
    alerts: {
      handler() { this.updateRadarChart(); this.updateMapFromAlerts(); }
    }
  },
  mounted() {
    this.$nextTick(async () => {
      await this.loadCampusMap();
      this.radarInstance = echarts.init(this.$refs.radarChart);
      this.updateRadarChart();
      window.addEventListener('resize', this.resizeChart);
      this.fetchGeoPoints();
      this.geoTimer = setInterval(this.fetchGeoPoints, 5000);
    });
  },
  beforeUnmount() {
    clearInterval(this.geoTimer);
    window.removeEventListener('resize', this.resizeChart);
    if (this.radarInstance) this.radarInstance.dispose();
    if (this.mapInstance) this.mapInstance.dispose();
  },
  methods: {
    formatBytes(bytes) {
      if (!bytes || bytes === 0) return '0 B';
      const k = 1024, sizes = ['B', 'KB', 'MB', 'GB'];
      const i = Math.floor(Math.log(bytes) / Math.log(k));
      return parseFloat((bytes / Math.pow(k, i)).toFixed(2)) + ' ' + sizes[i];
    },
    formatGeo(geo) {
      if (!geo) return '--';
      const building = geo.building || '';
      const zone = geo.zone || '';
      if (building && building !== '未知') return building;
      if (zone && zone !== '未知') return zone;
      return '--';
    },
    async loadCampusMap() {
      try {
        const serverIp = window.location.hostname;
        const res = await fetch(`http://${serverIp}:8080/campus.json`);
        const geoJson = await res.json();
        echarts.registerMap('campus', geoJson);
        this.mapRegistered = true;
        this.mapInstance = echarts.init(this.$refs.geoMap);
        this.initMapChart();
      } catch (e) {
        console.warn('[CampusMap] 校园地图数据加载失败，尝试备用路径', e);
        try {
          const res = await fetch('/campus.json');
          const geoJson = await res.json();
          echarts.registerMap('campus', geoJson);
          this.mapRegistered = true;
          this.mapInstance = echarts.init(this.$refs.geoMap);
          this.initMapChart();
        } catch (e2) {
          console.warn('[CampusMap] 备用路径也失败', e2);
        }
      }
    },
    initMapChart() {
      if (!this.mapInstance || !this.mapRegistered) return;
      this.mapInstance.setOption({
        title: {
          text: '校园威胁热力溯源',
          textStyle: { color: '#171717', fontSize: 16, fontWeight: 700 },
          top: 0, left: 0
        },
        tooltip: {
          trigger: 'item',
          backgroundColor: '#171717',
          borderColor: '#171717',
          textStyle: { color: '#fff', fontSize: 13 },
          padding: 12,
          borderRadius: 8,
          formatter: function(params) {
            if (params.componentType === 'geo') {
              const p = params.properties || {};
              if (p.type === 'road' || p.type === 'boundary') return '';
              return `<b>${p.name || ''}</b><br/>区域: ${p.zone || ''}`;
            }
            if (!params.data) return '';
            const d = params.data;
            return `<b>${d.name}</b><br/>威胁: ${d.threat_type || '未知'}<br/>等级: ${d.level === 'high' ? '高危' : '中危'}<br/>次数: ${d.value[2]}`;
          }
        },
        geo: {
          map: 'campus',
          roam: true,
          zoom: 1.15,
          center: [48, 38],
          itemStyle: {
            areaColor: function(params) {
              const type = (params.properties && params.properties.type) || '';
              const colorMap = {
                dormitory: '#e0d7fe', teaching: '#d0e4fc', admin: '#fef3c7',
                datacenter: '#fee2e2', sports: '#d1fae5', road: '#f0f0f0',
                boundary: '#faf9f7', gateway: '#fed7aa'
              };
              return colorMap[type] || '#f5f5f5';
            },
            borderColor: '#a3a3a3',
            borderWidth: 1
          },
          emphasis: {
            itemStyle: { areaColor: '#e4e4e7' },
            label: { color: '#171717', fontWeight: 600 }
          },
          label: {
            show: true,
            fontSize: 10,
            color: '#52525b',
            formatter: function(params) {
              const p = params.properties || {};
              if (p.type === 'road' || p.type === 'boundary') return '';
              return p.name || '';
            }
          },
          regions: []
        },
        series: [
          {
            name: '高危告警',
            type: 'effectScatter',
            coordinateSystem: 'geo',
            data: [],
            symbolSize: function(val) { return Math.max(10, val[2] * 6); },
            rippleEffect: { brushType: 'stroke', scale: 4, period: 3 },
            itemStyle: { color: '#ef4444' },
            label: { show: false }
          },
          {
            name: '中危告警',
            type: 'scatter',
            coordinateSystem: 'geo',
            data: [],
            symbolSize: function(val) { return Math.max(8, val[2] * 5); },
            itemStyle: { color: '#f59e0b', opacity: 0.9 },
            label: { show: false }
          }
        ]
      });
    },
    async fetchGeoPoints() {
      if (!this.mapInstance || !this.mapRegistered) return;
      try {
        const serverIp = window.location.hostname;
        const res = await fetch(`http://${serverIp}:8000/api/threat-geo`);
        const data = await res.json();
        if (data.geo_points) {
          this.geoPoints = data.geo_points;
          this.updateMapData(data.geo_points);
        }
      } catch (err) {
        // 静默
      }
    },
    updateMapFromAlerts() {
      if (!this.mapInstance || !this.mapRegistered) return;
      const highPoints = [];
      const medPoints = [];
      const seen = {};
      this.alerts.forEach(alert => {
        const geo = alert.geo;
        if (!geo || (geo.lat === 0 && geo.lon === 0)) return;
        const key = `${geo.lat}_${geo.lon}`;
        if (seen[key]) {
          seen[key].value[2] += 1;
        } else {
          const building = geo.building || '未知';
          const point = {
            name: `${building} (${alert.src_ip})`,
            value: [geo.lon, geo.lat, 1],
            threat_type: alert.category,
            level: alert.level,
            building: building,
            zone: geo.zone || '',
            src_ip: alert.src_ip,
            src_zone: alert.src_zone
          };
          seen[key] = point;
          if (alert.level === 'high') {
            highPoints.push(point);
          } else {
            medPoints.push(point);
          }
        }
      });
      this.mapInstance.setOption({
        series: [
          { data: highPoints },
          { data: medPoints }
        ]
      });
    },
    updateMapData(geoPoints) {
      if (!this.mapInstance || !this.mapRegistered) return;
      const highPoints = geoPoints.filter(p => p.level === 'high');
      const medPoints = geoPoints.filter(p => p.level !== 'high');
      this.mapInstance.setOption({
        series: [
          { data: highPoints },
          { data: medPoints }
        ]
      });
    },
    updateRadarChart() {
      if (!this.radarInstance) return;
      const option = {
        tooltip: { backgroundColor: '#171717', textStyle: { color: '#fff' }, borderWidth: 0, padding: 12, borderRadius: 8 },
        radar: {
          indicator: [
            { name: 'DDoS', max: Math.max(10, this.threatStats['DDoS攻击'] * 1.5) },
            { name: '扫描', max: Math.max(10, this.threatStats['端口扫描'] * 1.5) },
            { name: '蠕虫', max: Math.max(10, this.threatStats['蠕虫病毒'] * 1.5) },
            { name: '爬虫', max: Math.max(10, this.threatStats['异常爬虫'] * 1.5) },
            { name: '外泄', max: Math.max(10, this.threatStats['数据外泄'] * 1.5) }
          ],
          center: ['50%', '55%'], radius: '70%', splitNumber: 4, shape: 'circle',
          axisName: { color: '#52525b', fontWeight: 600, fontSize: 11 },
          splitArea: { areaStyle: { color: ['transparent'] } },
          axisLine: { lineStyle: { color: '#e4e4e7' } },
          splitLine: { lineStyle: { color: '#e4e4e7' } }
        },
        series: [{
          type: 'radar',
          data: [{
            value: [this.threatStats['DDoS攻击'], this.threatStats['端口扫描'], this.threatStats['蠕虫病毒'], this.threatStats['异常爬虫'], this.threatStats['数据外泄']]
          }],
          itemStyle: { color: '#43089f' },
          areaStyle: { color: 'rgba(67, 8, 159, 0.15)' },
          lineStyle: { width: 2 }
        }]
      };
      this.radarInstance.setOption(option);
    },
    resizeChart() {
      if (this.radarInstance) this.radarInstance.resize();
      if (this.mapInstance) this.mapInstance.resize();
    }
  }
}
</script>

