              <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"><line x1="18" y1="6" x2="6" y2="18"></line><line x1="6" y1="6" x2="18" y2="18"></line></svg>
            </button>
          </div>
          <div class="modal-map-wrapper" ref="modalMapWrapper">
            <div class="modal-map-inner" :style="modalMapStyle">
              <img
                :src="campusMapUrl"
                alt="校园安全态势地图"
                class="modal-map-img"
                draggable="false"
              />
              <!-- 全屏下的闪烁红点（同样使用百分比坐标） -->
              <div
                v-for="dot in alertDots"
                :key="dot.id"
                class="alert-dot"
                :class="{ 'dot-high': dot.level === 'high', 'dot-medium': dot.level === 'medium', 'dot-fading': dot.fading }"
                :style="{ left: dot.x, top: dot.y }"
              >
                <span class="dot-core"></span>
                <span class="dot-ripple"></span>
              </div>
            </div>
          </div>
          <!-- 缩放控制 -->
          <div class="zoom-controls">
            <button class="zoom-btn" @click="zoomIn" title="放大">
              <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5"><line x1="12" y1="5" x2="12" y2="19"></line><line x1="5" y1="12" x2="19" y2="12"></line></svg>
            </button>
            <span class="zoom-level">{{ Math.round(modalZoom * 100) }}%</span>
            <button class="zoom-btn" @click="zoomOut" title="缩小">
              <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5"><line x1="5" y1="12" x2="19" y2="12"></line></svg>
            </button>
            <button class="zoom-btn" @click="zoomReset" title="重置">
              <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><path d="M3 12a9 9 0 1 0 9-9 9.75 9.75 0 0 0-6.74 2.74L3 8"></path><path d="M3 3v5h5"></path></svg>
            </button>
          </div>
        </div>
      </div>
    </transition>
  </div>
</template>

<script>
import campusMapUrl from '@/assets/campus-map.jpg';

export default {
  name: 'MapTraceability',
  props: {
    alerts: { type: Array, default: () => [] }
  },
  data() {
    return {
      campusMapUrl,
      showFullscreen: false,
      modalZoom: 1,
      alertDots: [],
      mockTimer: null,
      dotIdCounter: 0,
      MAX_DOTS: 10,
      // 高发区域预设坐标（百分比）
      hotZones: [
        { name: '理工楼', x: '45%', y: '8%' },
        { name: '前3/前4/前5', x: '75%', y: '10%' },
        { name: '本13/本14/本15', x: '25%', y: '28%' },
        { name: '图书馆', x: '65%', y: '52%' }
      ]
    };
  },
  computed: {
    modalMapStyle() {
      return {
        transform: `scale(${this.modalZoom})`,
        transformOrigin: 'center center'
      };
    }
  },
  watch: {
    alerts: {
      handler(newAlerts) {
        if (newAlerts && newAlerts.length > 0) {
          this.addAlertDotFromData(newAlerts[newAlerts.length - 1]);
        }
      }
    }
  },
  mounted() {
    // 初始生成几个 Mock 告警点
    for (let i = 0; i < 3; i++) {
      this.addMockAlertDot();
    }
    // 定时模拟新告警（每 4-8 秒）
    this.scheduleNextMock();
  },
  beforeUnmount() {
    clearTimeout(this.mockTimer);
  },
  methods: {
    /* ---- 坐标与 Mock ---- */
    randomOffset(base, range) {
      // 在 base 百分比上添加 ±range 的随机偏移
      const baseVal = parseFloat(base);
      const offset = (Math.random() - 0.5) * 2 * range;
      return (baseVal + offset).toFixed(1) + '%';
    },
    pickHotZone() {
      return this.hotZones[Math.floor(Math.random() * this.hotZones.length)];
    },
    addMockAlertDot() {
      const zone = this.pickHotZone();
      const level = Math.random() > 0.4 ? 'high' : 'medium';
      this.pushDot({
        x: this.randomOffset(zone.x, 4),
        y: this.randomOffset(zone.y, 4),
        level,
        building: zone.name
      });
    },
    addAlertDotFromData(alert) {
      // 尝试根据 alert.geo 或 alert.src_zone 映射到地图坐标
      const geoMap = {
        '理工楼': { x: '45%', y: '8%' },
        '第一教学楼': { x: '52%', y: '85%' },
        '第二教学楼': { x: '65%', y: '85%' },
        '实验楼A': { x: '52%', y: '65%' },
        '实验楼B': { x: '63%', y: '65%' },
        '图书馆': { x: '83%', y: '85%' },
        '1号宿舍楼': { x: '9%', y: '84%' },
        '2号宿舍楼': { x: '22%', y: '84%' },
        '3号宿舍楼': { x: '34%', y: '84%' },
        '研究生公寓': { x: '19%', y: '65%' },
        '行政主楼': { x: '14%', y: '41%' },
        '信息中心': { x: '30%', y: '41%' },
        '教务处': { x: '14%', y: '25%' },
        '核心机房': { x: '53%', y: '41%' },
        '备份机房': { x: '65%', y: '41%' },
        '体育馆': { x: '12%', y: '13%' },
        '操场': { x: '30%', y: '13%' },
        '校园出口': { x: '50%', y: '3%' }
      };
      let x, y;
      const building = alert.geo?.building || '';
      const zone = alert.src_zone || '';
      if (building && geoMap[building]) {
        x = this.randomOffset(geoMap[building].x, 3);
        y = this.randomOffset(geoMap[building].y, 3);
      } else if (zone && geoMap[zone]) {
        x = this.randomOffset(geoMap[zone].x, 3);
        y = this.randomOffset(geoMap[zone].y, 3);
      } else {
        // fallback 到随机热点
        const hot = this.pickHotZone();
        x = this.randomOffset(hot.x, 4);
        y = this.randomOffset(hot.y, 4);
      }
      this.pushDot({ x, y, level: alert.level || 'medium', building: building || zone });
    },
    pushDot({ x, y, level, building }) {
      // 超出上限时标记最旧的为 fading
      if (this.alertDots.length >= this.MAX_DOTS) {
        const oldest = this.alertDots[0];
        if (!oldest.fading) {
          oldest.fading = true;
          setTimeout(() => {
            const idx = this.alertDots.findIndex(d => d.id === oldest.id);
            if (idx !== -1) this.alertDots.splice(idx, 1);
          }, 600);
        }
      }
      this.alertDots.push({
        id: ++this.dotIdCounter,
        x, y, level,
        building: building || '未知',
        fading: false
      });
    },
    scheduleNextMock() {
      const delay = 4000 + Math.random() * 4000; // 4-8秒
      this.mockTimer = setTimeout(() => {
        this.addMockAlertDot();
        this.scheduleNextMock();
      }, delay);
    },

    /* ---- 全屏交互 ---- */
    openFullscreen() {
      this.showFullscreen = true;
      this.modalZoom = 1;
      document.body.style.overflow = 'hidden';
    },
    closeFullscreen() {
      this.showFullscreen = false;
      document.body.style.overflow = '';
    },
    zoomIn() {
      this.modalZoom = Math.min(3, this.modalZoom + 0.25);
    },
    zoomOut() {
      this.modalZoom = Math.max(0.5, this.modalZoom - 0.25);
    },
    zoomReset() {
      this.modalZoom = 1;
    }
  }
};
</script>

